// ── Waveform bars helper ──────────────────────────────────────────────────────
function WaveformBars({ count = 60, playing = false, animated = false }) {
  const heights = Array.from({ length: count }, (_, i) => {
    const t = i / count;
    return 4 + 28 * Math.abs(Math.sin(t * Math.PI * 6 + 0.5)) * (0.4 + 0.6 * Math.random());
  });
  if (animated) {
    return (
      <div className="pp-waveform">
        {[...Array(count)].map((_, i) => (
          <div key={i} className="pp-wave-bar" style={{ "--d": `${i * 0.04}s` }} />
        ))}
      </div>
    );
  }
  return (
    <div className="pp-waveform-static">
      {heights.map((h, i) => (
        <div key={i} className="pp-wave-bar-static" style={{ height: `${h}px` }} />
      ))}
    </div>
  );
}

